func (this *AftermathCore) ParseTrade(rawTrade any, optionalArgs ...any) any {
	market := GetArg(optionalArgs, 0, nil)
	_ = market
	var trade any = this.SafeTrade(this.Extend(map[string]any{
		"info": rawTrade,
	}, rawTrade))
	AddElementToObject(trade, "id", "")
	AddElementToObject(trade, "order", nil)
	AddElementToObject(trade, "takerOrMaker", nil)
	AddElementToObject(trade, "timestamp", this.SafeInteger(rawTrade, "timestamp"))
	return trade
}

